class MockResponse:
    def __init__(self, status, payload):
        self.status_code = status
        self._payload = payload
    def json(self):
        return self._payload

resp = MockResponse(200, {'count': 2, 'items': [{'kind': 'shared_phone'}, {'kind': 'geo'}]})
print('status', resp.status_code)
print('count', resp.json()['count'])
print('kinds', [i['kind'] for i in resp.json()['items']])

def classify_status(code: int) -> str:
    if code == 200:
        return 'ok'
    if 400 <= code < 500:
        return 'client_error_no_retry'
    if 500 <= code < 600:
        return 'provider_error_retry'
    return 'other'

for c in [200, 400, 503]:
    print(c, classify_status(c))

def paginate(fetch_page, max_pages=10):
    items = []
    pages = 0
    pauses = 0
    for page in range(1, max_pages + 1):
        data = fetch_page(page)
        pages += 1
        if data.get('rate_limited'):
            pauses += 1
            continue
        items.extend(data.get('items') or [])
        if not data.get('next'):
            break
    return items, pages, pauses

def fetch_page(p):
    if p == 2:
        return {'rate_limited': True, 'items': [], 'next': True}
    if p == 1:
        return {'items': [1, 2], 'next': True}
    if p == 3:
        return {'items': [3, 4, 5], 'next': False}
    return {'items': [], 'next': False}

items, pages, pauses = paginate(fetch_page)
print('items', items)
print('pages_fetched', pages, 'rate_limit_pauses', pauses)

def fetch_with_retry(fn, max_attempts=3):
    last = None
    for attempt in range(1, max_attempts + 1):
        try:
            return fn(attempt)
        except TimeoutError as e:
            last = e
            if attempt == max_attempts:
                raise
    raise last

n = {'c': 0}
def flaky(attempt):
    n['c'] += 1
    if n['c'] < 2:
        raise TimeoutError('slow')
    return {'ok': True, 'attempt': attempt}

print(fetch_with_retry(flaky))

