ALLOWED = {"address", "city", "country"}

def allowed_for_public_geocoder(payload):
    keys = set(payload)
    if not keys.issubset(ALLOWED):
        return False
    banned = {'document_id', 'email', 'phone', 'dni'}
    return keys.isdisjoint(banned)

print(allowed_for_public_geocoder({'address': 'x', 'city': 'Lima'}))
print(allowed_for_public_geocoder({'address': 'x', 'document_id': 'D1'}))

def valid_lat_lon(lat, lon):
    try:
        la, lo = float(lat), float(lon)
    except (TypeError, ValueError):
        return False
    return -90 <= la <= 90 and -180 <= lo <= 180

print(valid_lat_lon(-12.04, -77.04), valid_lat_lon(91, 0), valid_lat_lon(0, 200), valid_lat_lon(0, 0))

